scripts.script:
if (!'true'.equalsIgnoreCase(project.properties.getProperty('hi.wsdl.codegen.skip', 'false').trim())) {
    return
}
def bd = project.build.directory as File
['generated-sources/wsimport', 'generated-sources/wsimport-parts', 'jaxws'].each { rel ->
    def d = new File(bd, rel)
    if (d.exists()) d.deleteDir()
}

import java.nio.file.Files
import java.nio.file.Path
import java.nio.file.Paths
String resolveTreePath(String raw, Path baseDir) {
    if (raw == null || raw.trim().isEmpty()) return null
    Path p = Paths.get(raw.trim())
    if (!p.isAbsolute()) {
        p = baseDir.resolve(raw.trim()).normalize()
    } else {
        p = p.normalize()
    }
    return p.toString()
}

Path baseDir = Paths.get(project.basedir as String)
String userCli = session.userProperties.getProperty('hi.wsdl.tree.root')
if (userCli != null && !userCli.trim().isEmpty()) {
    project.properties.setProperty('hi.wsdl.tree.root', resolveTreePath(userCli, baseDir))
    return
}
String envTree = System.getenv('HI_WSDL_TREE_ROOT')
if (envTree != null && !envTree.trim().isEmpty()) {
    project.properties.setProperty('hi.wsdl.tree.root', resolveTreePath(envTree, baseDir))
    return
}
String fromSettings = null
def settings = session.getSettings()
if (settings != null) {
    def activeIds = settings.getActiveProfiles()
    if (activeIds != null && !activeIds.isEmpty()) {
        try {
            def pmap = settings.getProfilesAsMap()
            if (pmap != null) {
                for (def pid : activeIds) {
                    if (fromSettings != null) break
                    def prof = pmap.get(pid)
                    if (prof?.getProperties() != null) {
                        String v = prof.getProperties().getProperty('hi.wsdl.tree.root')
                        if (v != null && !v.trim().isEmpty()) {
                            fromSettings = v.trim()
                        }
                    }
                }
            }
        } catch (Exception ignored) {
            settings.getProfiles()?.each { prof ->
                if (fromSettings == null && activeIds.contains(prof.getId())) {
                    String v = prof.getProperties()?.getProperty('hi.wsdl.tree.root')
                    if (v != null && !v.trim().isEmpty()) fromSettings = v.trim()
                }
            }
        }
    }
}
if (fromSettings != null) {
    project.properties.setProperty('hi.wsdl.tree.root', resolveTreePath(fromSettings, baseDir))
    return
}
project.properties.setProperty('hi.wsdl.tree.root',
        baseDir.resolve('wsdls').resolve('xml').toAbsolutePath().normalize().toString())
